curations.customCSS:
/* Card container (dark + red accent) */
.left {
  background-color: #1a1a1a;          /* solid dark background */
  border: 2px solid #FF6B6B;          /* red border */
  border-radius: 8px;
  padding: 12px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  position: relative;
  overflow: visible !important;       /* allow glow/shadows */
  flex-wrap: wrap;                    /* allow stacking if needed */
}

/* Remove default overlay */
.left:after {
  display: none !important;
}

/* Title + Subtitle stack */
.title-container {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
}

/* Title (pale gray with layered red glow) */
.title-container .level-title {
  color: #e0e0e0;
  font-size: 1.4em;
  font-weight: 700;
  margin-bottom: 2px;
  line-height: 1.2;
  text-shadow:
    0 0 6px rgba(255,107,107,0.8),  /* inner glow */
    0 0 12px rgba(255,68,68,0.7),   /* mid glow */
    0 0 24px rgba(255,0,0,0.6);     /* outer glow */
}

/* First letter emphasized (bright red) */
.title-container .level-title::first-letter {
  font-size: 2.5em;
  color: #FF4444;
  font-weight: 900;
  margin-right: 4px;
  line-height: 1;
}

/* Stats (labels = gray, values = red) */
.left > div > :first-child {
  color: #aaaaaa;
  font-weight: 500;
  text-shadow: 0 0 6px rgba(255,107,107,0.4);
}
.left > div > :last-child {
  color: #FF4444;
  font-weight: 600;
  text-shadow: 0 0 8px rgba(255,68,68,0.8);
}

/* Info box (frosted dark w/ red accent) */
.info {
  background: rgba(20,20,20,0.6);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(255,107,107,0.4);
  border-radius: 8px;
  padding: 12px;
  color: #e0e0e0;
  font-size: 0.9em;
}

/* Info rows */
.info-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  padding: 6px 0;
  border-bottom: 1px solid rgba(255,255,255,0.08);
}
.info-item:last-of-type { border-bottom: none; }

/* Label text */
.info-item > p {
  margin: 0;
  color: #aaaaaa;
  font-weight: 500;
}

/* Values (glowing red pill) */
.info-desc {
  background: rgba(40,40,40,0.6);
  border: 1px solid #FF6B6B;
  border-radius: 6px;
  padding: 4px 8px;
  font-weight: 600;
  color: #fff;
  white-space: nowrap;
  box-shadow:
    0 0 8px rgba(255,68,68,0.6),
    0 0 16px rgba(255,68,68,0.4);
}

/* “Full Info” button */
.info-button {
  width: 100%;
  margin-top: 10px;
  padding: 8px;
  border-radius: 6px;
  border: 1px solid #FF6B6B;
  background: transparent;
  color: #fff;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s ease;
}
.info-button:hover {
  background: #FF6B6B;
  color: #1a1a1a;
  box-shadow: 0 0 12px #FF6B6B;
}

